import React from "react";
import "./Login.css";
import TextField from "@material-ui/core/TextField";
import Button from "@material-ui/core/Button";
import CircularProgress from "@material-ui/core/CircularProgress";
import Container from "@material-ui/core/Container";
import Grid from "@material-ui/core/Grid";
import axios from "axios";

class Login extends React.Component {
  state = {
    ip: "",
    data: "",
    isLoading: false,
  };

  getClockState() {
    this.setState({ isLoading: true });
    if ((this.state.ip !== "", { timeout: 1000 })) {
      axios
        .get("http://" + this.state.ip)
        .then((result) =>
          this.setState({
            data: result.data,
            isLoading: false,
          })
        )
        .catch((error) =>
          this.setState({
            isLoading: false,
          })
        );
    }
  }

  handleChange = (e) => {
    this.setState({ ip: e.target.value });
  };

  checkIP = (e) => {
    this.getClockState();
  };

  keyPress = (e) => {
    if (e.key === "Enter") {
      this.checkIP();
    }
  };

  changeSpinner = (e) => {
    console.log('test')
    var spinner = document.getElementById("requestSpinner");
    if (this.state.isLoading) {
      spinner.style.display = "block";
    } else {
      spinner.style.display = "none";
    }
  }

  render() {
    return (
      <div className="Login">
        <Container maxWidth="xs">
          {this.state.ip}
          <Grid container spacing={2}>
            <Grid item xs={12}>
              <TextField
                id="outlined-basic"
                label="IP Address"
                variant="outlined"
                onChange={this.handleChange}
                onKeyDown={this.keyPress}
                value={this.state.ip}
                fullWidth={true}
              />
            </Grid>
            <Grid item xs={12}>
              <Button
                size="large"
                variant="contained"
                color="primary"
                onClick={this.checkIP}
                fullWidth={true}
              >
                Login
              </Button>
            </Grid>
            <Grid item xs={12}>
              <CircularProgress
                id="requestSpinner"
                onClick={this.changeSpinner}
              />
            </Grid>
          </Grid>
        </Container>
      </div>
    );
  }
}

export default Login;
